  Override the agent's default ChatOptions for this call:
    var runOpts = new ChatClientAgentRunOptions(
      new ChatOptions { 
        Temperature = 1.0,      // More creative
        MaxOutputTokens = 5000  // Longer response
      }
    );
    await agent.RunAsync("Explain quantum physics", session, runOpts, cts);

