================================================================================
                         COMPLETE USAGE EXAMPLE
================================================================================

// 1. Setup services
var services = new ServiceCollection()
    .AddLogging(b => b.AddConsole())
    .BuildServiceProvider();

// 2. Create chat client
var chatClient = new ChatClientBuilder()
    .UseOpenAI("gpt-4o-mini", apiKey: "sk-...")
    .Build();

// 3. Define your tools (via AIFunctionFactory or other means)
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        (string path) => File.ReadAllText(path),
        new() { Description = "Read a file from disk" }
    ),
    // More tools...
};

// 4a. Create agent directly
var agent = new ChatClientAgent(
    chatClient,
    instructions: "You help users work with files on their system.",
    name: "FileHelper",
    description: "File manipulation assistant",
    tools: tools,
    loggerFactory: services.GetRequiredService<ILoggerFactory>(),
    services: services
);

// 4b. OR use options pattern
var options = new ChatClientAgentOptions
{
    Name = "FileHelper",
    Description = "File manipulation assistant",
    ChatOptions = new ChatOptions { Temperature = 0.5 },
    AIContextProviders = new[] { 
        new FileAccessProvider(new FileAccessProviderOptions()) 
    }
};
var agent = new ChatClientAgent(chatClient, options, loggerFactory, services);

// 5. Create session for conversation
var session = await agent.CreateSessionAsync(
    conversationId: "user-123-session-456",
    cancellationToken: cts.Token
);

// 6. Run agent
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions { }
);

var response = await agent.RunAsync(
    message: "Read the file at /home/user/data.txt and summarize it",
    session: session,
    options: runOptions,
    cancellationToken: cts.Token
);

// 7. Process response
foreach (var message in response)
{
    if (message.Role == ChatRole.Assistant)
    {
        Console.WriteLine($"Agent: {message.Content}");
    }
    // Handle tool calls, etc.
}

// 8. Streaming example
await foreach (var message in agent.RunStreamingAsync(
    "What files are in the current directory?",
    session,
    runOptions,
    cts.Token))
{
    Console.Write(message.Content);  // Real-time output
}

